@substrate.jit
def _gemm_qk(s: S.Tensor((QK_COL_TILES, MFMA_ACC_SIZE), S.f32), r_q: S.Tensor((Q_BATCH_TILES, 2, 4), S.bf16), shm_kv_u128: S.Tensor((SHM_KV_SIZE // VEC_SIZE, 4), S.u32), wtid: S.u32):
