@substrate.jit
def _gemm_o(o: S.Tensor((O_TILES, MFMA_ACC_SIZE), S.f32), s_bf16: S.Tensor((QK_COL_TILES, MFMA_ACC_SIZE), S.bf16), shm_v_u128: S.Tensor((SHM_KV_SIZE // VEC_SIZE, 4), S.u32), wtid: S.u32):
