@substrate.jit
def _apply_causal_mask_slice(
    c: S.Tensor((MFMA_ACC_SIZE,), S.f32),
    row_idx_base: S.u32,
    col_idx_base: S.u32,
    tid: S.u32,
):
    c4 = S.view(c, S.Tensor((MFMA_ACC_SIZE // 4, 4), S.f32))
    neg_inf = S.convert(NEG_INF, S.f32)
    row = row_idx_base + (tid // WARP_SIZE) * SHM_TILE_M + tid % SHM_TILE_M
    col_group = ((tid % WARP_SIZE) // SHM_TILE_M) * 4
    for i in S.range(MFMA_ACC_SIZE // 4):
        col = col_idx_base + (i % 4) * 8 + col_group
        for j in S.range(4):
            if row < col + j:
                c4[i, j] = neg_inf

@substrate.jit
def _compute_row_max_slice(score_acc: S.Tensor((MFMA_ACC_SIZE,), S.f32)) -> S.f32:
    local_max = S.convert(NEG_INF, S.f32)
    for j in S.range(MFMA_ACC_SIZE):
        if score_acc[j] > local_max:
            local_max = score_acc[j]
    partner_max = S.shuffle_xor(local_max, 32, 64)
    block_max = local_max
    if partner_max > block_max:
        block_max = partner_max
    return block_max

@substrate.jit
def _compute_row_sum_slice(score_acc: S.Tensor((MFMA_ACC_SIZE,), S.f32)) -> S.f32:
    sum = S.convert(0.0, S.f32)
    for j in S.range(MFMA_ACC_SIZE):
        sum = sum + score_acc[j]
    partner_sum = S.shuffle_xor(sum, 32, 64)
    return sum + partner_sum

@substrate.jit
def _compute_ptilde_slice(score_acc: S.Tensor((MFMA_ACC_SIZE,), S.f32), row_max: S.f32):
    scale = S.convert(SCALE_LOG2, S.f32)
    row_max_scaled = row_max * scale
    for j in S.range(MFMA_ACC_SIZE):
        score_acc[j] = S.exp2(score_acc[j] * scale - row_max_scaled)

@substrate.jit
def _convert_to_bf16_score_slice(dst: S.Tensor((MFMA_ACC_SIZE,), S.bf16), src: S.Tensor((MFMA_ACC_SIZE,), S.f32)):
