    dst_u32 = S.view(dst, S.Tensor((MFMA_ACC_SIZE // 2,), S.u32))
    selector = S.convert(BF16_PACK_SELECTOR, S.u32)
    for j in S.range(MFMA_ACC_SIZE // 2):
        lo = S.bitcast(src_pairs[j, 0], S.u32)
        hi = S.bitcast(src_pairs[j, 1], S.u32)
        dst_u32[j] = S.amdgpu.perm(hi, lo, selector)

