@substrate.jit
def _normalize_softmax_lse(l: S.f32, dst: S.Tensor((O_TILES, MFMA_ACC_SIZE), S.bf16), o_f32: S.Tensor((O_TILES, MFMA_ACC_SIZE), S.f32)):
    inv = S.convert(1.0, S.f32) / l
    for i in S.range(O_TILES):
        for j in S.range(MFMA_ACC_SIZE):
            o_f32[i, j] = o_f32[i, j] * inv
