@substrate.jit
def _unpack_o(shm_o: S.Tensor((BLOCK_ROWS * HEAD_DIM // 4,), S.u64), o_bf16: S.Tensor((O_TILES, MFMA_ACC_SIZE), S.bf16), wid: S.u32, wtid: S.u32):
    r_o_u64 = S.view(o_bf16, S.Tensor((O_TILES * 4,), S.u64))
    shm_row_stride = HEAD_DIM // 4
    unpack_warp_stride = MMA_N * shm_row_stride
    lane = wtid % MMA_N
    lane_group = wtid // MMA_N
    for i in S.range(O_TILES * 4):
        shm_o[wid * unpack_warp_stride + i * 2 + lane * shm_row_stride + lane_group] = r_o_u64[i]

@substrate.jit
def _write_result(
    out_rsrc: S.Tensor((4,), S.u32),
    shm_o_vec: S.Tensor((BLOCK_ROWS * HEAD_DIM // VEC_SIZE, 4), S.u32),
    tid: S.u32,
    stride_q: S.u32,
    out_base: S.u32,
):
    zero = S.convert(0, S.u32)
    idx = tid
    for _ in S.range(BLOCK_ROWS * HEAD_DIM // VEC_SIZE // THREADS):
        row = idx // (HEAD_DIM // VEC_SIZE)
        col = idx % (HEAD_DIM // VEC_SIZE)
        out_off = (out_base + row * stride_q // VEC_SIZE + col) * U128_BYTES
        S.amdgpu.raw_buffer_store_x4(shm_o_vec[idx], out_rsrc, zero, out_off, 0)
        idx += THREADS

@substrate.jit
