        dst[i] = src[i]

@substrate.jit
def _main_loop_pipelined_exact(
    r_o: S.Tensor((O_TILES, MFMA_ACC_SIZE), S.f32),
    r_q: S.Tensor((Q_BATCH_TILES, 2, 4), S.bf16),
    r_s0_init_bf16: S.Tensor((MFMA_ACC_SIZE,), S.bf16),
    softmax_state: S.Tensor((4,), S.f32),
    shm_buf: S.Tensor((SHM_SHARED_DWORDS // 4, 4), S.u32),
    s_k0_u128: S.Tensor((SHM_K_SLICE_VECS, 4), S.u32),
    s_k1_u128: S.Tensor((SHM_K_SLICE_VECS, 4), S.u32),
    s_v_u128: S.Tensor((SHM_V_SLICE_VECS, 4), S.u32),
    stride_kv: S.u32,
    k_rsrc: S.Tensor((4,), S.u32),
    v_rsrc: S.Tensor((4,), S.u32),
    l_k_off: S.u32,
    l_v_off: S.u32,
    k1_lds_base_bytes: S.u32,
    row_idx_base: S.u32,
    min_k_tile: S.u32,
    max_k_tile: S.u32,
    wid: S.u32,
    wtid: S.u32,
    tid: S.u32,
    group_wid: S.u32,
):
    r_k = S.make_local((Q_BATCH_TILES, 2, 4), S.bf16)
    r_v = S.make_local((O_TILES, O_CHUNK_PER_SLICE, 2, 4), S.bf16)
    g_v0_pipelined = S.make_local((4,), S.u32)
    g_v1_pipelined = S.make_local((4,), S.u32)
    r_s0 = S.make_local((MFMA_ACC_SIZE,), S.f32)
    r_s1 = S.make_local((MFMA_ACC_SIZE,), S.f32)
    r_s0_bf16 = S.make_local((MFMA_ACC_SIZE,), S.bf16)
    r_s1_bf16 = S.make_local((MFMA_ACC_SIZE,), S.bf16)
    mi = softmax_state[0]
    l = softmax_state[1]
    mi_new = softmax_state[2]
    wg0_drain_row_sum = softmax_state[3]
    scale = S.convert(SCALE_LOG2, S.f32)

    _copy_score_slice_bf16(r_s0_bf16, r_s0_init_bf16)
    _tiled_layout_fetch_global_v_packed_slice(g_v0_pipelined, stride_kv, v_rsrc, l_v_off, wid, wtid)

    if wid < Q_WARPS_PER_GROUP:
        _fetch_k_regs_slice(r_k, s_k1_u128, wtid)
        _tiled_layout_fetch_global_k_to_shm_async_slice(
            shm_buf,
            stride_kv,
            k_rsrc,
            l_k_off + BLOCK_COLS * stride_kv * BF16_BYTES,
            group_wid,
            wtid,
            0,
        )
        _tiled_layout_fetch_global_v_packed_slice(
            g_v1_pipelined,
            stride_kv,
            v_rsrc,
            l_v_off + BC_PER_SLICE * stride_kv * BF16_BYTES,
            wid,
            wtid,
        )
        S.amdgpu.s_waitcnt(0, 7, 15)
    S.syncthreads()

    for tile_iter in S.range(max_k_tile + 1):
        i = tile_iter + 1
        is_drain_iter = i == max_k_tile + 1

        if wid < Q_WARPS_PER_GROUP:
            _clear_s_slice(r_s1)
            _gemm_qk_major_slice(r_s1, r_q, r_k)
        else:
            _fetch_k_regs_slice(r_k, s_k1_u128, wtid)
            _tiled_layout_fetch_global_v_packed_slice(
                g_v1_pipelined,
                stride_kv,
                v_rsrc,
                l_v_off + (i - 1) * BLOCK_COLS * stride_kv * BF16_BYTES + BC_PER_SLICE * stride_kv * BF16_BYTES,
                wid,
                wtid,
            )
        S.syncthreads()

        if wid < Q_WARPS_PER_GROUP:
            _gemm_qk_minor_slice(r_s1, r_q, r_k)
        else:
            _tiled_layout_store_shm_v_transposed_packed_slice(s_v_u128, g_v0_pipelined, wid, wtid)
        S.syncthreads()

        if wid < Q_WARPS_PER_GROUP:
            _tiled_layout_store_shm_v_transposed_packed_slice(s_v_u128, g_v0_pipelined, wid, wtid)
        else:
            _clear_s_slice(r_s1)
            _gemm_qk_major_slice(r_s1, r_q, r_k)
        S.syncthreads()

        if wid < Q_WARPS_PER_GROUP:
            _fetch_v_regs_slice(r_v, s_v_u128, wtid)
            if i - 1 >= min_k_tile:
                _apply_causal_mask_slice(r_s1, row_idx_base, (i - 1) * BLOCK_COLS + BC_PER_SLICE, tid)
            if not is_drain_iter:
                _tiled_layout_fetch_global_v_packed_slice(
                    g_v0_pipelined,
                    stride_kv,
                    v_rsrc,
                    l_v_off + i * BLOCK_COLS * stride_kv * BF16_BYTES,
                    wid,
                    wtid,
                )
        else:
            _gemm_qk_minor_slice(r_s1, r_q, r_k)
        S.syncthreads()

        if wid < Q_WARPS_PER_GROUP:
            _gemm_o_slice(r_o, r_s0_bf16, r_v)
            mi_new = _compute_row_max_slice(r_s1)
            if mi > mi_new:
                mi_new = mi
            _compute_ptilde_slice(r_s1, mi_new)
        else:
            _fetch_v_regs_slice(r_v, s_v_u128, wtid)
            if i - 1 >= min_k_tile:
                _apply_causal_mask_slice(r_s1, row_idx_base, (i - 1) * BLOCK_COLS + BC_PER_SLICE, tid)
            if not is_drain_iter:
                _tiled_layout_fetch_global_v_packed_slice(
                    g_v0_pipelined,
                    stride_kv,
                    v_rsrc,
                    l_v_off + i * BLOCK_COLS * stride_kv * BF16_BYTES,
                    wid,
                    wtid,
                )

        S.amdgpu.s_waitcnt(0, 0, 0)
        S.syncthreads()

        if wid < Q_WARPS_PER_GROUP:
            row_sum = _compute_row_sum_slice(r_s1)
            if is_drain_iter:
                wg0_drain_row_sum = row_sum
            else:
                scaling = S.exp2((mi - mi_new) * scale)
                l = scaling * l + row_sum
                _multiply_alpha(scaling, r_o)
                mi = mi_new
            _convert_to_bf16_score_slice(r_s1_bf16, r_s1)
            _fetch_k_regs_slice(r_k, s_k0_u128, wtid)
            _clear_s_slice(r_s0)
            _gemm_qk_major_slice(r_s0, r_q, r_k)
        else:
            _gemm_o_slice(r_o, r_s0_bf16, r_v)
            mi_new = _compute_row_max_slice(r_s1)
            if mi > mi_new:
                mi_new = mi
            _compute_ptilde_slice(r_s1, mi_new)
            if not is_drain_iter:
                row_sum = _compute_row_sum_slice(r_s1)
                scaling = S.exp2((mi - mi_new) * scale)
                l = scaling * l + row_sum
                _multiply_alpha(scaling, r_o)
                mi = mi_new
                _convert_to_bf16_score_slice(r_s1_bf16, r_s1)
                _fetch_k_regs_slice(r_k, s_k0_u128, wtid)
                _tiled_layout_fetch_global_k_to_shm_async_slice(
                    shm_buf,
                    stride_kv,
                    k_rsrc,
                    l_k_off + i * BLOCK_COLS * stride_kv * BF16_BYTES + BC_PER_SLICE * stride_kv * BF16_BYTES,
                    group_wid,
                    wtid,
                    k1_lds_base_bytes,
                )
        S.syncthreads()

        if not is_drain_iter:
            if wid < Q_WARPS_PER_GROUP:
                _gemm_qk_minor_slice(r_s0, r_q, r_k)
                if i >= min_k_tile:
                    _apply_causal_mask_slice(r_s0, row_idx_base, i * BLOCK_COLS, tid)
            else:
                _tiled_layout_store_shm_v_transposed_packed_slice(s_v_u128, g_v1_pipelined, wid, wtid)
            S.syncthreads()

            if wid < Q_WARPS_PER_GROUP:
                _tiled_layout_store_shm_v_transposed_packed_slice(s_v_u128, g_v1_pipelined, wid, wtid)
            else:
                _clear_s_slice(r_s0)
                _gemm_qk_major_slice(r_s0, r_q, r_k)
            S.syncthreads()

            if wid < Q_WARPS_PER_GROUP:
                _fetch_v_regs_slice(r_v, s_v_u128, wtid)
                _tiled_layout_fetch_global_v_packed_slice(
                    g_v1_pipelined,
                    stride_kv,
                    v_rsrc,
                    l_v_off + i * BLOCK_COLS * stride_kv * BF16_BYTES + BC_PER_SLICE * stride_kv * BF16_BYTES,
                    wid,
                    wtid,
                )
            else:
                _gemm_qk_minor_slice(r_s0, r_q, r_k)
                if i >= min_k_tile:
                    _apply_causal_mask_slice(r_s0, row_idx_base, i * BLOCK_COLS, tid)
            S.syncthreads()

            S.amdgpu.s_waitcnt(0, 0, 0)
            S.syncthreads()
            if wid < Q_WARPS_PER_GROUP:
                _gemm_o_slice(r_o, r_s1_bf16, r_v)
                mi_new = _compute_row_max_slice(r_s0)
                if mi > mi_new:
                    mi_new = mi
                _compute_ptilde_slice(r_s0, mi_new)
                row_sum = _compute_row_sum_slice(r_s0)
                scaling = S.exp2((mi - mi_new) * scale)
                l = scaling * l + row_sum
                _multiply_alpha(scaling, r_o)
                mi = mi_new
                _convert_to_bf16_score_slice(r_s0_bf16, r_s0)
                _fetch_k_regs_slice(r_k, s_k1_u128, wtid)
            else:
                _fetch_v_regs_slice(r_v, s_v_u128, wtid)
                _gemm_o_slice(r_o, r_s1_bf16, r_v)
                mi_new = _compute_row_max_slice(r_s0)
                if mi > mi_new:
                    mi_new = mi
                _compute_ptilde_slice(r_s0, mi_new)
                row_sum = _compute_row_sum_slice(r_s0)
                scaling = S.exp2((mi - mi_new) * scale)
                l = scaling * l + row_sum
                _multiply_alpha(scaling, r_o)
                mi = mi_new
                _convert_to_bf16_score_slice(r_s0_bf16, r_s0)
            S.syncthreads()

            if i < max_k_tile and wid < Q_WARPS_PER_GROUP:
                _tiled_layout_fetch_global_k_to_shm_async_slice(
                    shm_buf,
                    stride_kv,
                    k_rsrc,
                    l_k_off + (i + 1) * BLOCK_COLS * stride_kv * BF16_BYTES,
                    group_wid,
                    wtid,
                    0,
                )

    S.amdgpu.s_waitcnt(0, 0, 0)
    S.syncthreads()
    _tiled_layout_store_shm_v_transposed_packed_slice(s_v_u128, g_v1_pipelined, wid, wtid)
    S.amdgpu.s_waitcnt(63, 7, 0)
    S.syncthreads()
    if wid < Q_WARPS_PER_GROUP:
        scaling = S.exp2((mi - mi_new) * scale)
        l = scaling * l + wg0_drain_row_sum
        _multiply_alpha(scaling, r_o)
        mi = mi_new
    else:
        row_sum = _compute_row_sum_slice(r_s1)
        scaling = S.exp2((mi - mi_new) * scale)
        l = scaling * l + row_sum
        _multiply_alpha(scaling, r_o)
        mi = mi_new
        _convert_to_bf16_score_slice(r_s1_bf16, r_s1)
    _fetch_v_regs_slice(r_v, s_v_u128, wtid)
    _gemm_o_slice(r_o, r_s1_bf16, r_v)

    softmax_state[0] = mi
    softmax_state[1] = l
    softmax_state[2] = mi_new
    softmax_state[3] = wg0_drain_row_sum


@substrate.jit
def _flash_attn_kernel(
     out_ptr: S.Pointer(S.bf16),
     q_ptr: S.Pointer(S.bf16),
     k_ptr: S.Pointer(S.bf16),
     v_ptr: S.Pointer(S.bf16),
     seq_ptr: S.Pointer(S.u32),
     gqa_ratio: S.u32,
     heads_kv: S.u32,
):
    heads_q = heads_kv * gqa_ratio
    stride_q = heads_q * HEAD_DIM
    stride_kv = heads_kv * HEAD_DIM

    g_seq = S.make_tensor(seq_ptr, S.u32, S.make_layout((S.grid_dim(2) + 1,), (1,)))

    idx_q = S.block_id(0)
    idx_h = S.block_id(1)
    seq_id = S.block_id(2)
    tid = S.thread_id(0)
    seq_begin = g_seq[seq_id]
    seq_end = g_seq[seq_id + 1]
    seq_len = seq_end - seq_begin 
    wid = tid // WARP_SIZE
    wtid = tid % WARP_SIZE

    q_memref = S.make_tensor(q_ptr, S.bf16, S.make_layout((seq_end * stride_q,), (1,)))
    k_memref = S.make_tensor(k_ptr, S.bf16, S.make_layout((seq_end * stride_kv,), (1,)))
    v_memref = S.make_tensor(v_ptr, S.bf16, S.make_layout((seq_end * stride_kv,), (1,)))
    out_vec_memref = S.make_tensor(out_ptr, S.u32, S.make_layout((seq_end * stride_q // VEC_SIZE, 4), (4, 1)))
    q_rsrc = S.amdgpu.make_rsrc(q_memref, seq_end * stride_q * BF16_BYTES)
    k_rsrc = S.amdgpu.make_rsrc(k_memref, seq_end * stride_kv * BF16_BYTES)
    v_rsrc = S.amdgpu.make_rsrc(v_memref, seq_end * stride_kv * BF16_BYTES)
    l_q_off = (seq_begin * stride_q + idx_q * BLOCK_ROWS * stride_q + idx_h * HEAD_DIM) * BF16_BYTES 
    l_k_off = (seq_begin * stride_kv + (idx_h // gqa_ratio) * HEAD_DIM) * BF16_BYTES
    l_v_off = (seq_begin * stride_kv + (idx_h // gqa_ratio) * HEAD_DIM) * BF16_BYTES

    shm_buf = S.make_shared((SHM_SHARED_DWORDS // 4, 4), S.u32)
    shm_o = S.view(shm_buf, S.Tensor((BLOCK_ROWS * HEAD_DIM // 4,), S.u64))
    s_k0_u128 = S.subview(shm_buf, (0, 0), (SHM_K_SLICE_VECS, 4), (1, 1))
    s_k1_u128 = S.subview(shm_buf, (SHM_K_SLICE_VECS, 0), (SHM_K_SLICE_VECS, 4), (1, 1))
    s_q_u128 = S.subview(shm_buf, (SHM_K_TOTAL_VECS, 0), (SHM_Q_STAGE_VECS, 4), (1, 1))
    s_v_u128 = S.subview(shm_buf, (SHM_K_TOTAL_VECS, 0), (SHM_V_SLICE_VECS, 4), (1, 1))

    if idx_q * BLOCK_ROWS >= seq_len:
        return

    q_lds_base_bytes = SHM_K_TOTAL_WORDS * 4
    k1_lds_base_bytes = SHM_K_SLICE_WORDS * 4
    group_wid = wid % Q_WARPS_PER_GROUP
    wgid = wid // Q_WARPS_PER_GROUP
    r_q = S.make_local((Q_BATCH_TILES, 2, 4), S.bf16)
    _load_q_2stage(r_q, shm_buf, s_q_u128, stride_q, q_rsrc, l_q_off, q_lds_base_bytes, wid, wtid, tid)

    r_o = S.make_local((O_TILES, MFMA_ACC_SIZE), S.f32)
    for i in S.range(O_TILES):
        for j in S.range(MFMA_ACC_SIZE):
            r_o[i, j] = 0

    r_k = S.make_local((Q_BATCH_TILES, 2, 4), S.bf16)
    r_s0 = S.make_local((MFMA_ACC_SIZE,), S.f32)
    r_s0_bf16 = S.make_local((MFMA_ACC_SIZE,), S.bf16)
    mi = S.convert(0.0, S.f32)
    l = S.convert(0.0, S.f32)
    row_idx_base = idx_q * BLOCK_ROWS
    min_k_tile = row_idx_base // BLOCK_COLS
    max_k_col = S.min(seq_len - 1, row_idx_base + BLOCK_ROWS - 1)
    max_k_tile = max_k_col // BLOCK_COLS

    S.amdgpu.s_waitcnt(0, 0, 0)
    S.syncthreads()
    if wgid == 0:
        _tiled_layout_fetch_global_k_to_shm_async_slice(
            shm_buf, stride_kv, k_rsrc, l_k_off, group_wid, wtid, 0
        )
    else:
        _tiled_layout_fetch_global_k_to_shm_async_slice(
            shm_buf,
            stride_kv,
            k_rsrc,
            l_k_off + BC_PER_SLICE * stride_kv * BF16_BYTES,
            group_wid,
            wtid,
            k1_lds_base_bytes,
        )
    S.amdgpu.s_waitcnt(0, 7, 15)
    S.syncthreads()

    _fetch_k_regs_slice(r_k, s_k0_u128, wtid)
    _clear_s_slice(r_s0)
    _gemm_qk_slice(r_s0, r_q, r_k)
    if 0 >= min_k_tile:
        _apply_causal_mask_slice(r_s0, row_idx_base, 0, tid)
    mi = _compute_row_max_slice(r_s0)
    neg_inf = S.convert(NEG_INF, S.f32)
    if mi == neg_inf:
        mi = S.convert(0.0, S.f32)
    _compute_ptilde_slice(r_s0, mi)
    l = _compute_row_sum_slice(r_s0)
    _convert_to_bf16_score_slice(r_s0_bf16, r_s0)
    softmax_state = S.make_local((4,), S.f32)
    softmax_state[0] = mi
    softmax_state[1] = l
    softmax_state[2] = S.convert(0.0, S.f32)
    softmax_state[3] = S.convert(0.0, S.f32)
    if wid < Q_WARPS_PER_GROUP:
        _main_loop_pipelined_exact(
            r_o,
            r_q,
            r_s0_bf16,
            softmax_state,
            shm_buf,
            s_k0_u128,
            s_k1_u128,
            s_v_u128,
            stride_kv,
            k_rsrc,
            v_rsrc,
            l_k_off,
            l_v_off,
            k1_lds_base_bytes,
            row_idx_base,
            min_k_tile,
            max_k_tile,
            wid,
            wtid,
            tid,
            group_wid,
        )
    else:
        _main_loop_pipelined_exact(
            r_o,
            r_q,
            r_s0_bf16,
            softmax_state,
            shm_buf,
            s_k0_u128,
            s_k1_u128,
            s_v_u128,
            stride_kv,
            k_rsrc,
            v_rsrc,
            l_k_off,
            l_v_off,
            k1_lds_base_bytes,
            row_idx_base,
            min_k_tile,
            max_k_tile,
            wid,
            wtid,
            tid,
            group_wid,
        )
    l = softmax_state[1]

    r_o_bf16 = S.make_local((O_TILES, MFMA_ACC_SIZE), S.bf16)
    _normalize_softmax_lse(l, r_o_bf16, r_o)

    s_o_vec = S.view(shm_o, S.Tensor((BLOCK_ROWS * HEAD_DIM // VEC_SIZE, 4), S.u32))
    S.syncthreads()
    _unpack_o(shm_o, r_o_bf16, wid, wtid)
    S.syncthreads()

    out_base = (seq_begin * stride_q + idx_q * BLOCK_ROWS * stride_q + idx_h * HEAD_DIM) // VEC_SIZE
    remaining = seq_len - idx_q * BLOCK_ROWS
    valid_rows = remaining
    if BLOCK_ROWS < valid_rows:
        valid_rows = BLOCK_ROWS
    out_range = (out_base + valid_rows * stride_q // VEC_SIZE - stride_q // VEC_SIZE + HEAD_DIM // VEC_SIZE) * U128_BYTES
    out_rsrc = S.amdgpu.make_rsrc(out_vec_memref, out_range)
    _write_result(out_rsrc, s_o_vec, tid, stride_q, out_base)

def _flash_attn_impl(
    q: torch.Tensor,
    k: torch.Tensor,
    v: torch.Tensor,
    seq_ptr: torch.Tensor,
    out: torch.Tensor | None = None,
) -> torch.Tensor:
    _validate_packed_flash_attn_inputs(q, k, v, seq_ptr)

    seq_ptr_host = seq_ptr.to(device="cpu", dtype=torch.int64)
    seq_lens = torch.diff(seq_ptr_host)
    num_seqs = int(seq_ptr_host.numel() - 1)
    max_seq_len = int(seq_lens.max().item())
    num_q_blocks = (max_seq_len + BLOCK_ROWS - 1) // BLOCK_ROWS
    if bool((seq_lens % BLOCK_ROWS).any().item()):
        raise NotImplementedError(
            "flash_attn currently requires every sequence length to be a multiple of BLOCK_ROWS"
        )

    heads_q = q.shape[1]
    heads_kv = k.shape[1]
    gqa_ratio = heads_q // heads_kv

    if out is None:
        out = torch.zeros((q.shape[0], heads_q, HEAD_DIM), dtype=torch.bfloat16, device=q.device)

    seq_ptr_dev = seq_ptr.to(device=q.device, dtype=torch.int32)
    _flash_attn_kernel[lambda: ((num_q_blocks, heads_q, num_seqs), (THREADS, 1, 1))](
        out,
        q,
        k,
        v,
        seq_ptr_dev,
        gqa_ratio,
        heads_kv,
        num_warps=NUM_WARPS,
    )
    return out

def flash_attn(
    q: torch.Tensor,
    k: torch.Tensor,
    v: torch.Tensor,
    seq_ptr: torch.Tensor,
) -> torch.Tensor:
    return _flash_attn_impl(q, k, v, seq_ptr)

__all__ = [
    "flash_attn",
]

